SELECT borough_id, COUNT(postal_code_id) AS number_of_postal_codes
FROM postal_codes
GROUP BY borough_id;

SELECT postal_code, last_updated
FROM postal_codes
ORDER BY last_updated DESC;

SELECT postal_code
FROM postal_codes
WHERE postal_code_id = 1;

SELECT postal_code
FROM postal_codes
WHERE latitude = (SELECT MAX(latitude) FROM postal_codes);
